// Extract ticket info from Slack message
const message = $input.first().json;
const ticketId = 'INC-' + String(Math.floor(10000 + Math.random() * 90000));

return [{
  json: {
    ticket_id: ticketId,
    raw_text: message.text || message.event?.text || '',
    user_id: message.user || message.event?.user || 'unknown',
    user_name: message.user_name || message.event?.user || 'unknown',
    channel: message.channel || message.event?.channel || '',
    thread_ts: message.ts || message.event?.ts || '',
    source: 'slack',
    timestamp: new Date().toISOString()
  }
}];

// Parse classification from Groq response
const rawResponse = $input.first().json.output || $input.first().json.text || '';
const ticketData = $('Extract Message').first().json;

let classification;
try {
  // Try to extract JSON from the response
  let jsonStr = rawResponse;

  // Handle markdown code blocks
  const jsonMatch = rawResponse.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    jsonStr = jsonMatch[1].trim();
  }

  // Handle case where response has text before/after JSON
  const braceMatch = rawResponse.match(/\{[\s\S]*\}/);
  if (braceMatch) {
    jsonStr = braceMatch[0];
  }

  classification = JSON.parse(jsonStr);
} catch (e) {
  // Fallback classification if parsing fails
  classification = {
    category: 'service_request',
    subcategory: 'unknown',
    intent: 'unknown',
    priority: 'P3',
    confidence: 0.30,
    summary: 'Unable to parse classification. Routing to human triage.',
    search_terms: ticketData.raw_text.split(' ').slice(0, 5).join(' '),
    is_security_incident: false,
    reasoning: 'Classification parsing failed. Defaulting to human triage.'
  };
}

// Validate and set defaults
const validPriorities = ['P1', 'P2', 'P3', 'P4'];
if (!validPriorities.includes(classification.priority)) {
  classification.priority = 'P3';
}

if (typeof classification.confidence !== 'number' || classification.confidence < 0 || classification.confidence > 1) {
  classification.confidence = 0.50;
}

// Force security check on keywords
const securityKeywords = ['phishing', 'malware', 'suspicious', 'hack', 'breach', 'unauthorized', 'virus', 'ransomware'];
const textLower = ticketData.raw_text.toLowerCase();
for (const keyword of securityKeywords) {
  if (textLower.includes(keyword)) {
    classification.is_security_incident = true;
    classification.priority = 'P1';
    break;
  }
}

return [{
  json: {
    ...ticketData,
    classification
  }
}];

// Determine routing based on classification + policy
const data = $('Parse Classification').first().json;
const classification = data.classification;
const kbResults = $('Search Knowledge Base').first().json || [];
const policyResults = $('Fetch Policy Rules').first().json || [];

const policy = Array.isArray(policyResults) && policyResults.length > 0 
  ? policyResults[0] 
  : { max_automation_level: 'L0', requires_approval: true, confidence_threshold: 0.85, tools_allowed: [], escalation_target: '#tier2-support' };

let route;
let routeReason;

if (classification.is_security_incident) {
  route = 'escalate';
  routeReason = 'Security incident - always escalate';
} else if (classification.confidence < 0.60) {
  route = 'human_triage';
  routeReason = `Confidence too low (${classification.confidence}) for any automation`;
} else if (classification.confidence < policy.confidence_threshold) {
  route = 'hitl';
  routeReason = `Confidence (${classification.confidence}) below policy threshold (${policy.confidence_threshold})`;
} else if (policy.max_automation_level === 'L3' && !policy.requires_approval) {
  route = 'lights_out';
  routeReason = 'L3 policy - full automation allowed';
} else if (policy.max_automation_level === 'L2' || policy.max_automation_level === 'L1') {
  route = 'hitl';
  routeReason = `${policy.max_automation_level} policy - requires human approval`;
} else {
  route = 'human_triage';
  routeReason = 'Default safe routing - no matching automation policy';
}

return [{
  json: {
    ...data,
    kb_results: Array.isArray(kbResults) ? kbResults : [],
    policy,
    route,
    route_reason: routeReason
  }
}];

