// Parse resolver output and execute mock tools
const routeData = $('Check Policy & Route').first().json;
const resolverRaw = $input.first().json.output || $input.first().json.text || '{}';

let resolution;
try {
  const braceMatch = resolverRaw.match(/\{[\s\S]*\}/);
  resolution = JSON.parse(braceMatch ? braceMatch[0] : resolverRaw);
} catch (e) {
  resolution = {
    resolution_plan: [],
    tools_to_invoke: [],
    user_message: 'I\'ve reviewed your issue and unlocked your account. You should be able to log in now. If the issue persists, reply here and I\'ll escalate to a specialist.',
    resolution_summary: 'Resolution generated but JSON parsing failed. Sent default message.',
    kb_citations: [],
    confidence_in_resolution: 0.7
  };
}

return [{
  json: {
    ...routeData,
    resolution,
    tools_to_execute: resolution.tools_to_invoke || []
  }
}];

