// Parse escalation output
const routeData = $('Check Policy & Route').first().json;
const escRaw = $input.first().json.output || $input.first().json.text || '{}';

let escalation;
try {
  const braceMatch = escRaw.match(/\{[\s\S]*\}/);
  escalation = JSON.parse(braceMatch ? braceMatch[0] : escRaw);
} catch (e) {
  escalation = {
    escalation_summary: routeData.classification.summary || 'Ticket requires human review',
    what_was_tried: ['AI classification attempted'],
    what_was_found: [],
    recommended_team: routeData.classification.is_security_incident ? '#secops' : '#tier2-support',
    recommended_priority: routeData.classification.priority,
    context_for_agent: `User reported: ${routeData.raw_text}. Classification: ${routeData.classification.intent} (${routeData.classification.confidence} confidence).`,
    suggested_next_steps: ['Review ticket and contact user for more details'],
    user_communication: 'Your ticket has been escalated to our specialist team. We\'ll follow up shortly.'
  };
}

// Force security incidents to #secops
const targetChannel = routeData.classification.is_security_incident 
  ? '#secops' 
  : (escalation.recommended_team || routeData.policy.escalation_target || '#tier2-support');

return [{
  json: {
    ...routeData,
    escalation,
    target_channel: targetChannel
  }
}];

